using SlideGenerator.Application.Scanning.Models.Sheets;
using SlideGenerator.Application.Scanning.Models.Slides;

namespace SlideGenerator.Application.Scanning.Models;

/// <summary>
///     Aggregated scan result for one presentation and one workbook.
/// </summary>
public sealed record ScanningInfo(PresentationInfo Presentation, WorkbookInfo Workbook);

namespace SlideGenerator.Application.Systems.Abstractions;

/// <summary>
///     Provides HTTP operations required by application-level cloud resolvers.
/// </summary>
public interface IHttpClientService
{
    /// <summary>
    ///     Resolves a URI to its final request URI after redirect handling.
    /// </summary>
    /// <param name="uri">The URI to request.</param>
    /// <param name="cancellationToken">Cancellation token for the asynchronous operation.</param>
    /// <returns>The final request URI after redirect handling, or the original URI if unavailable.</returns>
    Task<Uri> ResolveFinalUriAsync(Uri uri, CancellationToken cancellationToken = default);

    /// <summary>
    ///     Downloads the response body as a string.
    /// </summary>
    /// <param name="uri">The URI to request.</param>
    /// <param name="cancellationToken">Cancellation token for the asynchronous operation.</param>
    /// <returns>The response body as a string.</returns>
    Task<string> GetStringAsync(Uri uri, CancellationToken cancellationToken = default);
}
